// AIManagerAI defines model for AIManagerAI.
type AIManagerAI struct {
	// CustomerId The unique identifier of the associated customer. Returned from the `GET /customers` response.
	CustomerId *string `json:"customer_id,omitempty"`

	// Detail Detailed information about the AI.
	Detail *string `json:"detail,omitempty"`

	// DirectHash Hash for direct access via SIP URI sip:direct.<hash>@sip.voipbin.net. Returned from the resource's `direct_hash` field.
	DirectHash *string `json:"direct_hash,omitempty"`

	// EngineKey API key or authentication key for the AI engine. Write-only; not returned in responses.
	EngineKey *string `json:"engine_key,omitempty"`

	// EngineModel Model of the AI engine. Uses target.model format (e.g., openai.gpt-5). The target prefix identifies the provider, and the model name follows after the dot.
	EngineModel *AIManagerAIEngineModel `json:"engine_model,omitempty"`

	// Id The unique identifier of the AI.
	Id *string `json:"id,omitempty"`

	// InitPrompt Initial prompt to configure the AI's behavior.
	InitPrompt *string `json:"init_prompt,omitempty"`

	// Name Name of the AI.
	Name *string `json:"name,omitempty"`

	// Parameter Custom key-value configuration data specific to the AI engine type.
	Parameter *map[string]interface{} `json:"parameter,omitempty"`

	// RagId The knowledge base ID for the search_knowledge tool. Returned from the `id` field of the `GET /rags` response. When set, the AI assistant can search this knowledge base during voice calls.
	RagId *string `json:"rag_id,omitempty"`

	// SmartTurnEnabled Enable smart turn detection using Pipecat's LocalSmartTurnAnalyzerV3. When enabled, forces VAD stop_secs to 0.2 for optimal turn-taking.
	SmartTurnEnabled *bool `json:"smart_turn_enabled,omitempty"`

	// SttLanguage STT language in BCP-47 format (e.g., ko-KR, en-US). Empty for auto-detect.
	SttLanguage *string `json:"stt_language,omitempty"`

	// SttType Speech-to-text provider type.
	SttType *AIManagerAISTTType `json:"stt_type,omitempty"`

	// TmCreate Timestamp when the AI was created.
	TmCreate *string `json:"tm_create,omitempty"`

	// TmDelete Timestamp when the AI was deleted.
	TmDelete *string `json:"tm_delete,omitempty"`

	// TmUpdate Timestamp when the AI was last updated.
	TmUpdate *string `json:"tm_update,omitempty"`

	// ToolNames List of tool names enabled for this AI. Use `["all"]` to enable all available tools. See the Tool Functions documentation for detailed descriptions of each tool.
	ToolNames *[]AIManagerToolName `json:"tool_names,omitempty"`

	// TtsType Text-to-speech provider type.
	TtsType *AIManagerAITTSType `json:"tts_type,omitempty"`

	// TtsVoiceId Text-to-speech voice identifier.
	TtsVoiceId *string `json:"tts_voice_id,omitempty"`

	// VadConfig Voice Activity Detection configuration. Omitted fields use Pipecat defaults (confidence=0.7, start_secs=0.2, stop_secs=0.2, min_volume=0.6).
	VadConfig *AIManagerVADConfig `json:"vad_config,omitempty"`
}

